import{_ as t,o as e,c as o,a2 as c}from"./chunks/framework.BWuWLRhz.js";const g=JSON.parse('{"title":"35 · 命令与配置速查表","description":"","frontmatter":{"head":[["meta",{"property":"og:site_name","content":"David Studio AI 编程指南"}]]},"headers":[],"relativePath":"codex/35-cheatsheet.md","filePath":"codex/35-cheatsheet.md"}'),a={name:"codex/35-cheatsheet.md"};function s(r,d,i,l,n,h){return e(),o("div",null,[...d[0]||(d[0]=[c(`<h1 id="_35-·-命令与配置速查表" tabindex="-1">35 · 命令与配置速查表 <a class="header-anchor" href="#_35-·-命令与配置速查表" aria-label="Permalink to &quot;35 · 命令与配置速查表&quot;">​</a></h1><blockquote><p>📚 <strong>系列导航</strong>：上一篇〔<a href="./34-capstone">34 综合实战</a> 〕带你把前面所有零件串成一个完整项目跑了一遍，那是「合」。这一篇反过来——把散落在三十多篇里的命令、标志、配置键全部抽出来，压成一张你能贴在显示器边上的速查表。下一篇〔<a href="./36-best-practices">36 最佳实践</a> 〕再从「怎么用得对」收尾整个 Codex 篇。</p></blockquote><p>说句丢人的事。</p><p>用 Codex 的头两个月，我电脑里躺着一个叫 <code>codex-备忘.txt</code> 的文件，里面歪歪扭扭记着「导出 JSON 是 <code>--json</code>」「写最后一条消息到文件是 <code>-o</code>」这类东西。问题是我记得乱，每次要用 <code>codex exec</code> 把结果写进文件，我先翻这个 txt，翻不到就翻 shell 历史 <code>history | grep codex</code>，再翻不到就开浏览器搜官方文档——一条命令的事，能折腾我五分钟。</p><p>更蠢的是配置。有回我想给某个项目临时关掉沙箱网络，记得有个 <code>sandbox_workspace_write</code> 开头的键，但后面接什么忘得一干二净，<code>network</code> ？<code>net_access</code> ？我对着 <code>config.toml</code> 瞎试，试到 Codex 启动报错，最后还是去翻 config-reference 才知道是 <code>sandbox_workspace_write.network_access</code> 。那一刻我决定：<strong>与其每次现翻，不如一次性把高频命令和配置抠出来排成表，要哪个扫一眼就走。</strong></p><p>这一篇就是那张表的成品。它不讲原理（原理前面都讲过了），只干一件事——<strong>让你查得快、抄得准、不用再开浏览器。</strong></p><p><strong>看完这一篇，你会拿到：</strong></p><ul><li>一张覆盖安装登录、CLI 命令与标志、斜杠命令、<code>config.toml</code> 高频配置项的速查表</li><li>权限沙箱档位、模型与推理强度的对照表，照着填不踩坑</li><li>MCP（Model Context Protocol，模型上下文协议）/ 子代理 / Skills 这些进阶能力的「关键入口」清单，知道从哪条命令切进去</li><li>一个能跑通验证的小例子，确认你查到的命令真在你本地生效</li></ul><blockquote><p>⚠️ 命令、标志、配置键以官方文档为准，<strong>会随版本变化</strong>；模型名、默认值随版本与你的账号而变，<strong>一律以你本地 <code>codex --help</code> 和 <code>config.toml</code> 实际行为为准</strong>；通过 <code>codex --version</code> 确认当前版本。下面标了「实验性」的，开头会注明，用之前留个心眼。</p></blockquote><hr><h2 id="_01-安装与登录" tabindex="-1">01 安装与登录 <a class="header-anchor" href="#_01-安装与登录" aria-label="Permalink to &quot;01 安装与登录&quot;">​</a></h2><p>第一次装、换机器、CI 里重新拉起，最常用就这几条。<strong>类比：这是 Codex 的「开机三件套」——装上、登进去、确认登成功，缺一步它都不干活。</strong></p><p>国内网络下，安装脚本和登录走 OAuth 都可能需要<strong>魔法上网</strong>，否则容易卡在下载或回调那一步。</p><table tabindex="0"><thead><tr><th>目的</th><th>命令</th><th>平台 / 备注</th></tr></thead><tbody><tr><td>标准安装（脚本）</td><td><code>curl -fsSL https://chatgpt.com/codex/install.sh | sh</code></td><td>macOS / Linux</td></tr><tr><td>标准安装（脚本）</td><td><code>powershell -ExecutionPolicy ByPass -c &quot;irm https://chatgpt.com/codex/install.ps1 | iex&quot;</code></td><td>Windows</td></tr><tr><td>用 npm 装</td><td><code>npm install -g @openai/codex</code></td><td>全平台，需 Node</td></tr><tr><td>用 Homebrew 装</td><td><code>brew install --cask codex</code></td><td>macOS</td></tr><tr><td>更新到最新版</td><td><code>codex update</code></td><td>发行版支持自更新时可用</td></tr><tr><td>登录（浏览器 OAuth）</td><td><code>codex login</code></td><td>默认方式，开浏览器登 ChatGPT</td></tr><tr><td>登录（设备码）</td><td><code>codex login --device-auth</code></td><td>无法开浏览器时用（如远程服务器）</td></tr><tr><td>用 API Key 登录</td><td><code>printenv OPENAI_API_KEY | codex login --with-api-key</code></td><td>从 stdin 读 key</td></tr><tr><td>查登录状态</td><td><code>codex login status</code></td><td>已登录退出码为 <code>0</code>，适合脚本判断</td></tr><tr><td>退出登录</td><td><code>codex logout</code></td><td>清掉本地凭据</td></tr><tr><td>体检诊断</td><td><code>codex doctor</code></td><td>装好/出问题时跑一把，自检安装、配置、认证、Git 等</td></tr></tbody></table><blockquote><p>💡 一句话总结：装完先 <code>codex doctor</code> 跑一遍体检，再用 <code>codex login status</code> 确认登录态，比直接开干少走一半弯路。</p></blockquote><hr><h2 id="_02-codex-cli-常用命令与标志" tabindex="-1">02 codex CLI 常用命令与标志 <a class="header-anchor" href="#_02-codex-cli-常用命令与标志" aria-label="Permalink to &quot;02 codex CLI 常用命令与标志&quot;">​</a></h2><p>这是全篇最核心的一块。<strong>类比：<code>codex</code> 是主程序，后面跟的是「子命令」（去哪），再后面的 <code>--xxx</code> 是「标志」（怎么去）。</strong> 先记子命令，再记标志，组合起来就是一条完整命令。</p><h3 id="常用子命令" tabindex="-1">常用子命令 <a class="header-anchor" href="#常用子命令" aria-label="Permalink to &quot;常用子命令&quot;">​</a></h3><table tabindex="0"><thead><tr><th>子命令</th><th>干什么</th><th>成熟度</th></tr></thead><tbody><tr><td><code>codex</code></td><td>启动交互式终端界面（TUI，Terminal User Interface），不带子命令时就是它</td><td>稳定</td></tr><tr><td><code>codex exec</code></td><td>非交互跑一次，跑完即退；短写 <code>codex e</code></td><td>稳定</td></tr><tr><td><code>codex resume</code></td><td>接着上一次的交互会话继续聊</td><td>稳定</td></tr><tr><td><code>codex fork</code></td><td>把某次会话「分叉」成新线程，原记录不动</td><td>稳定</td></tr><tr><td><code>codex apply</code></td><td>把云端任务生成的 diff 应用到本地；短写 <code>codex a</code></td><td>稳定</td></tr><tr><td><code>codex mcp</code></td><td>管理 MCP 服务器（list / add / remove / login）</td><td>实验性</td></tr><tr><td><code>codex features</code></td><td>列出功能开关并持久启用/禁用</td><td>稳定</td></tr><tr><td><code>codex completion</code></td><td>生成 shell 补全脚本</td><td>稳定</td></tr></tbody></table><h3 id="高频全局标志-跟在-codex-或多数子命令后" tabindex="-1">高频全局标志（跟在 <code>codex</code> 或多数子命令后） <a class="header-anchor" href="#高频全局标志-跟在-codex-或多数子命令后" aria-label="Permalink to &quot;高频全局标志（跟在 \`codex\` 或多数子命令后）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>标志</th><th>作用</th><th>取值 / 备注</th></tr></thead><tbody><tr><td><code>--model</code> / <code>-m</code></td><td>临时换模型</td><td>如 <code>-m gpt-5.5</code></td></tr><tr><td><code>--image</code> / <code>-i</code></td><td>附带图片给首条提示</td><td>多张用逗号分隔或重复 <code>-i</code></td></tr><tr><td><code>--cd</code> / <code>-C</code></td><td>指定工作目录后再开干</td><td>接一个路径</td></tr><tr><td><code>--sandbox</code> / <code>-s</code></td><td>选沙箱档位</td><td><code>read-only</code> / <code>workspace-write</code> / <code>danger-full-access</code></td></tr><tr><td><code>--ask-for-approval</code> / <code>-a</code></td><td>选审批时机</td><td><code>untrusted</code> / <code>on-request</code> / <code>never</code></td></tr><tr><td><code>--search</code></td><td>开实时联网搜索</td><td>把 <code>web_search</code> 切到 <code>live</code>（默认是 <code>cached</code>）</td></tr><tr><td><code>--add-dir</code></td><td>额外给某目录写权限</td><td>可重复，比直接放开全盘安全</td></tr><tr><td><code>--profile</code> / <code>-p</code></td><td>套用某个配置 profile</td><td>叠在基础配置之上</td></tr><tr><td><code>--config</code> / <code>-c</code></td><td>命令行临时改配置</td><td><code>-c key=value</code>，能解析成 TOML 就按 TOML</td></tr><tr><td><code>--yolo</code></td><td>跳过一切审批和沙箱</td><td><strong>危险</strong>，只在隔离环境里用</td></tr></tbody></table><h3 id="codex-exec-非交互-专属高频标志" tabindex="-1"><code>codex exec</code>（非交互）专属高频标志 <a class="header-anchor" href="#codex-exec-非交互-专属高频标志" aria-label="Permalink to &quot;\`codex exec\`（非交互）专属高频标志&quot;">​</a></h3><p>这是写脚本、跑 CI 最常用的一组。<strong>类比：交互模式像你在饭店点菜，<code>codex exec</code> 像下单外卖——下了就走，结果送到你指定的地方。</strong></p><table tabindex="0"><thead><tr><th>标志</th><th>作用</th></tr></thead><tbody><tr><td><code>PROMPT</code> 写 <code>-</code></td><td>从 stdin 读提示词（如 <code>cat prompt.txt | codex exec -</code>）</td></tr><tr><td><code>--json</code></td><td>输出按行的 JSON（JSONL）事件流，方便 <code>jq</code> 解析</td></tr><tr><td><code>--output-last-message</code> / <code>-o</code></td><td>把最终回复<strong>写到文件</strong>（同时仍打印到 stdout）</td></tr><tr><td><code>--output-schema</code></td><td>给个 JSON Schema，强制最终输出符合该结构</td></tr><tr><td><code>--skip-git-repo-check</code></td><td>允许在非 Git 目录里跑</td></tr><tr><td><code>--ephemeral</code></td><td>不在磁盘留会话记录</td></tr><tr><td><code>--full-auto</code></td><td><strong>已弃用</strong>的兼容标志，会打警告；新脚本改用 <code>--sandbox workspace-write</code></td></tr><tr><td><code>codex exec resume --last</code></td><td>接着最近一次 exec 会话继续</td></tr></tbody></table><blockquote><p>💡 一句话总结：<code>-m</code> 换模型、<code>-s</code> 调沙箱、<code>-a</code> 调审批、<code>-o</code>/<code>--json</code> 收结果——把这四件事记牢，命令行八成场景就齐了。</p></blockquote><hr><h2 id="_03-斜杠命令-在-tui-里输入" tabindex="-1">03 斜杠命令（在 TUI 里输入） <a class="header-anchor" href="#_03-斜杠命令-在-tui-里输入" aria-label="Permalink to &quot;03 斜杠命令（在 TUI 里输入）&quot;">​</a></h2><p>斜杠命令只在交互界面里用——进了 <code>codex</code> 那个全屏界面，敲 <code>/</code> 弹出菜单。<strong>类比：它们是会话里的「快捷按钮」，不用退出去敲命令，打个斜杠就地切。</strong></p><p>下面是我自己用得最勤的一批。完整清单以你本地 <code>/</code> 弹出的菜单为准，不同版本会有增减。</p><table tabindex="0"><thead><tr><th>斜杠命令</th><th>干什么</th></tr></thead><tbody><tr><td><code>/model</code></td><td>切当前模型（可选时连推理强度一起调）</td></tr><tr><td><code>/status</code></td><td>看当前模型、审批策略、可写目录、剩余上下文</td></tr><tr><td><code>/compact</code></td><td>把长对话压成摘要，腾出上下文空间</td></tr><tr><td><code>/diff</code></td><td>看 Git diff，连没跟踪的新文件也显示</td></tr><tr><td><code>/permissions</code></td><td>中途调整 Codex 能不问就做哪些事</td></tr><tr><td><code>/review</code></td><td>让 Codex 审一遍你当前工作区的改动</td></tr><tr><td><code>/init</code></td><td>在当前目录生成 <code>AGENTS.md</code> 脚手架</td></tr><tr><td><code>/mcp</code></td><td>列出当前会话能调的 MCP 工具（加 <code>verbose</code> 看详情）</td></tr><tr><td><code>/skills</code></td><td>浏览并选用本地 skill</td></tr><tr><td><code>/agent</code></td><td>在已派生的子代理线程之间切换</td></tr><tr><td><code>/fast</code></td><td>开/关当前模型的 Fast 服务层（<code>/fast on</code>/<code>off</code>/<code>status</code>）</td></tr><tr><td><code>/new</code></td><td>同一 CLI 会话里开一段全新对话</td></tr><tr><td><code>/clear</code></td><td>清屏并开新对话</td></tr><tr><td><code>/quit</code> 或 <code>/exit</code></td><td>退出 CLI</td></tr></tbody></table><p>提醒一句：<code>/fast</code> 是「模型目录（catalog）驱动」的——当前模型如果不提供 Fast 层，菜单里压根不出现 <code>/fast</code> ，别以为是 bug 。</p><blockquote><p>💡 一句话总结：会话里最高频的就四个——<code>/model</code> 换脑子、<code>/status</code> 看现状、<code>/compact</code> 清场子、<code>/diff</code> 验成果，先把这四个练成肌肉记忆。</p></blockquote><hr><h2 id="_04-config-toml-常用配置项" tabindex="-1">04 config.toml 常用配置项 <a class="header-anchor" href="#_04-config-toml-常用配置项" aria-label="Permalink to &quot;04 config.toml 常用配置项&quot;">​</a></h2><p>配置文件在 <code>~/.codex/config.toml</code> （TOML 格式），是 Codex 的「长期记忆」。<strong>类比：命令行标志是「这一趟怎么走」，<code>config.toml</code> 是「以后默认都这么走」。</strong> 项目里还能放 <code>.codex/config.toml</code> 做项目级覆盖（需先信任该项目）。</p><p>下面只列高频项，全量见官方 config-reference 。</p><table tabindex="0"><thead><tr><th>配置键</th><th>作用</th><th>取值示例</th></tr></thead><tbody><tr><td><code>model</code></td><td>默认模型</td><td><code>&quot;gpt-5.5&quot;</code></td></tr><tr><td><code>model_reasoning_effort</code></td><td>推理强度（可选值随模型变化）</td><td>常见：<code>none</code> / <code>minimal</code> / <code>low</code> / <code>medium</code> / <code>high</code> / <code>xhigh</code></td></tr><tr><td><code>model_reasoning_summary</code></td><td>推理摘要详细度</td><td><code>auto</code> / <code>concise</code> / <code>detailed</code> / <code>none</code></td></tr><tr><td><code>service_tier</code></td><td>服务层级</td><td><code>flex</code> / <code>fast</code>（提速相关，搭配 <code>/fast</code>）</td></tr><tr><td><code>sandbox_mode</code></td><td>沙箱档位</td><td><code>read-only</code> / <code>workspace-write</code> / <code>danger-full-access</code></td></tr><tr><td><code>sandbox_workspace_write.network_access</code></td><td>工作区写模式下是否放开联网</td><td><code>true</code> / <code>false</code></td></tr><tr><td><code>sandbox_workspace_write.writable_roots</code></td><td>额外可写目录</td><td><code>[&quot;/path/a&quot;, &quot;/path/b&quot;]</code></td></tr><tr><td><code>approval_policy</code></td><td>审批策略</td><td><code>untrusted</code> / <code>on-request</code> / <code>never</code></td></tr><tr><td><code>web_search</code></td><td>联网搜索模式</td><td><code>disabled</code> / <code>cached</code> / <code>live</code>（默认 <code>cached</code>）</td></tr><tr><td><code>review_model</code></td><td><code>/review</code> 用的模型</td><td>不填则用当前会话模型</td></tr><tr><td><code>model_instructions_file</code></td><td>用某文件替代内置指令</td><td>一个路径</td></tr></tbody></table><p>一个最小可用的 <code>config.toml</code> 长这样，复制进去改改就能用：</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">model = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;gpt-5.5&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">model_reasoning_effort = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;medium&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sandbox_mode = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;workspace-write&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">approval_policy = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;on-request&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sandbox_workspace_write</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">network_access = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span></span></code></pre></div><blockquote><p>💡 一句话总结：<code>config.toml</code> 里把 <code>model</code>、<code>model_reasoning_effort</code>、<code>sandbox_mode</code>、<code>approval_policy</code> 四个键定好，就等于给 Codex 定了「默认人格」，剩下临时调用标志去覆盖。</p></blockquote><hr><h2 id="_05-权限-沙箱档位" tabindex="-1">05 权限 / 沙箱档位 <a class="header-anchor" href="#_05-权限-沙箱档位" aria-label="Permalink to &quot;05 权限 / 沙箱档位&quot;">​</a></h2><p>沙箱决定 Codex 能动你机器到什么程度，审批决定它动手前问不问你。这俩是组合拳。<strong>类比：沙箱是「实习生能进哪几个房间」，审批是「他动手前要不要先喊你一声」。</strong></p><table tabindex="0"><thead><tr><th>沙箱档位（<code>--sandbox</code> / <code>sandbox_mode</code>）</th><th>能干什么</th><th>适合场景</th></tr></thead><tbody><tr><td><code>read-only</code></td><td>只读，不能改文件</td><td>让它先看、先分析，不动代码</td></tr><tr><td><code>workspace-write</code></td><td>能改工作区内文件</td><td>日常本地开发的甜区</td></tr><tr><td><code>danger-full-access</code></td><td>全盘读写、放开网络</td><td><strong>只在隔离容器 / CI runner 里用</strong></td></tr></tbody></table><table tabindex="0"><thead><tr><th>审批时机（<code>--ask-for-approval</code> / <code>approval_policy</code>）</th><th>含义</th></tr></thead><tbody><tr><td><code>untrusted</code></td><td>只对它认为可信的命令放行，其余都问</td></tr><tr><td><code>on-request</code></td><td>交互式跑的推荐值，需要时才暂停问你</td></tr><tr><td><code>never</code></td><td>从不问，非交互/CI 跑用这个</td></tr></tbody></table><p>官方给本地低摩擦干活的推荐组合就一句：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">codex</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --sandbox</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> workspace-write</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --ask-for-approval</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> on-request</span></span></code></pre></div><p>补充两个我踩过的点：想给 Codex 多开一个可写目录，<strong>别图省事直接上 <code>danger-full-access</code>，用 <code>--add-dir</code> 精准放行那一个目录</strong>就够；<code>--full-auto</code> 是老的兼容写法，已弃用，新脚本一律改成 <code>--sandbox workspace-write</code>。</p><blockquote><p>💡 一句话总结：本地默认「<code>workspace-write</code> + <code>on-request</code>」，CI 用「指定沙箱 + <code>never</code>」，要放权先想能不能用 <code>--add-dir</code> 替代全开。</p></blockquote><hr><h2 id="_06-模型与推理强度对照" tabindex="-1">06 模型与推理强度对照 <a class="header-anchor" href="#_06-模型与推理强度对照" aria-label="Permalink to &quot;06 模型与推理强度对照&quot;">​</a></h2><p>选模型是「派谁去」，调推理强度是「让他想多久再动手」，两个旋钮独立。<strong>类比：模型是请的人，推理强度是给他的思考时间——简单活儿别让高手慢慢琢磨，硬骨头也别让新手草草交差。</strong></p><table tabindex="0"><thead><tr><th>模型</th><th>定位</th><th>什么时候用</th></tr></thead><tbody><tr><td><code>gpt-5.5</code></td><td>旗舰，最强</td><td>复杂编程、重构、研究类硬活</td></tr><tr><td><code>gpt-5.4-mini</code></td><td>轻量、快、省</td><td>杂活、批量任务、子代理</td></tr><tr><td><code>gpt-5.3-codex-spark</code></td><td>即时型研究预览（仅 ChatGPT Pro）</td><td>求近乎秒回的实时迭代</td></tr></tbody></table><p><code>gpt-5.2</code> 和 <code>gpt-5.3-codex</code> 已弃用，别再写进配置或 <code>--model</code> 里。</p><p>推理强度由 <code>model_reasoning_effort</code> 控制，<strong>可选档位随模型变化</strong>（哪几档能用，以 <code>/model</code> 面板和当前模型文档为准），常见档位：</p><table tabindex="0"><thead><tr><th>取值</th><th>思考力度</th><th>典型场景</th></tr></thead><tbody><tr><td><code>none</code></td><td>完全不额外想（模型相关）</td><td>纯指令执行</td></tr><tr><td><code>minimal</code></td><td>几乎不想，最快</td><td>改 typo、重命名、跑个命令</td></tr><tr><td><code>low</code></td><td>略想一下</td><td>小修小补</td></tr><tr><td><code>medium</code></td><td>默认甜区</td><td>绝大多数日常编程</td></tr><tr><td><code>high</code></td><td>深思熟虑</td><td>多文件改动、设计权衡</td></tr><tr><td><code>xhigh</code></td><td>顶格（模型相关）</td><td>真·硬骨头，确定值得等</td></tr></tbody></table><p>我自己的默认就是「<code>gpt-5.5</code> + <code>medium</code>」打天下，只在确定要啃硬骨头时手动提到 <code>high</code>。前面第 30 篇说过我犯的蠢——长期锁死 <code>xhigh</code> 改个 typo 等一分钟，<strong>那种「最强焦虑」省下来的，比你以为的多得多。</strong></p><blockquote><p>💡 一句话总结：日常「旗舰 + <code>medium</code>」，体力活降到 <code>minimal</code>/<code>low</code>，硬骨头才提 <code>high</code>/<code>xhigh</code>，弃用模型一个别碰。</p></blockquote><hr><h2 id="_07-mcp-子代理-skills-关键入口" tabindex="-1">07 MCP / 子代理 / Skills 关键入口 <a class="header-anchor" href="#_07-mcp-子代理-skills-关键入口" aria-label="Permalink to &quot;07 MCP / 子代理 / Skills 关键入口&quot;">​</a></h2><p>这三块都是进阶能力，原理前面各有专篇（第 20、21、22 篇）。这里只给「从哪条命令/配置切进去」的入口，省得你回头翻。<strong>类比：这是三扇门的「门把手位置」——记住把手在哪，推门进去的细节回专篇看。</strong></p><table tabindex="0"><thead><tr><th>能力</th><th>关键入口</th><th>说明</th></tr></thead><tbody><tr><td>MCP（外接工具，像 USB 接口）</td><td><code>codex mcp list</code> / <code>codex mcp add &lt;name&gt; ...</code></td><td>命令行管服务器；会话里 <code>/mcp</code> 看可用工具（实验性）</td></tr><tr><td>MCP（HTTP 服务器登录）</td><td><code>codex mcp login &lt;name&gt;</code></td><td>仅支持 OAuth 的 streamable HTTP 服务器</td></tr><tr><td>配置 MCP 服务器</td><td><code>config.toml</code> 里 <code>[mcp_servers.&lt;id&gt;]</code></td><td><code>command</code>/<code>args</code>/<code>url</code> 等键定义一台服务器</td></tr><tr><td>子代理（并行干活）</td><td><code>config.toml</code> 里 <code>[agents]</code> / <code>agents.&lt;name&gt;.*</code></td><td><code>max_threads</code> 默认 <code>6</code>；会话里 <code>/agent</code> 切线程</td></tr><tr><td>Skills（任务专用技能）</td><td>会话里 <code>/skills</code></td><td>浏览并选用；<code>config.toml</code> 里用 <code>[[skills.config]]</code>（带 <code>path</code>/<code>enabled</code>）做启用覆盖</td></tr></tbody></table><p>注意 <code>codex mcp</code> 整组目前标的是「实验性」，子命令和行为可能随版本变，用前以 <code>codex mcp --help</code> 为准。</p><blockquote><p>💡 一句话总结：MCP 走 <code>codex mcp</code> 命令、子代理靠 <code>[agents]</code> 配置 + <code>/agent</code> 切换、Skills 用 <code>/skills</code> 选——记住这三个入口，进阶能力就不会「不知道从哪开始」。</p></blockquote><hr><h2 id="_08-动手-验证你查到的命令真在生效" tabindex="-1">08 动手：验证你查到的命令真在生效 <a class="header-anchor" href="#_08-动手-验证你查到的命令真在生效" aria-label="Permalink to &quot;08 动手：验证你查到的命令真在生效&quot;">​</a></h2><p>速查表抄得再齐，不如亲手跑一条确认它在你本地真能用。下面这条最小例子，不依赖任何已有项目，三步走。</p><p>第一步，确认登录状态（不改任何东西，纯查）：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">codex</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> login</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span></code></pre></div><p>预期输出：已登录会打印当前认证方式，<strong>退出码为 <code>0</code></strong>；没登录会提示你去 <code>codex login</code>。</p><p>第二步，跑一条非交互命令，让它把结果写进文件——同时验证 <code>codex exec</code>、<code>-o</code> 和只读沙箱三件事：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">codex</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> exec</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --sandbox</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> read-only</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /tmp/codex-check.txt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;用一句话说明当前目录是不是一个 Git 仓库&quot;</span></span></code></pre></div><p>预期：终端打印出那句话，同时 <code>/tmp/codex-check.txt</code>（Windows 上换成你的临时目录）里也写下了同一句。打开文件能看到内容，就说明 <code>-o</code> 生效了。</p><p>第三步，确认你查的标志名没记错——直接问 CLI 自己：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">codex</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> exec</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --help</span></span></code></pre></div><p>预期：列出 <code>codex exec</code> 支持的所有标志。<strong>任何时候你拿不准某个标志存不存在、叫什么，<code>--help</code> 永远是比这张表更新、更准的那一份。</strong></p><blockquote><p>💡 一句话总结：<code>login status</code> 验登录、<code>codex exec -o</code> 验命令真在干活、<code>--help</code> 验标志名没记错——这三条跑通，说明速查表对你本地是「活」的。</p></blockquote><hr><h2 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to &quot;小结&quot;">​</a></h2><p>这一篇没讲新概念，把前面三十多篇里的「手感」压成了七张表：</p><ul><li><strong>开机三件套</strong>：安装、<code>codex login</code>、<code>codex login status</code> 确认，出问题先 <code>codex doctor</code>。</li><li><strong>CLI 命令与标志</strong>：子命令记「去哪」，标志记「怎么去」，<code>-m</code>/<code>-s</code>/<code>-a</code>/<code>-o</code>/<code>--json</code> 是高频五件套。</li><li><strong>斜杠命令</strong>：会话内 <code>/model</code>、<code>/status</code>、<code>/compact</code>、<code>/diff</code> 先练成肌肉记忆。</li><li><strong><code>config.toml</code></strong>：<code>model</code>、<code>model_reasoning_effort</code>、<code>sandbox_mode</code>、<code>approval_policy</code> 定好默认人格。</li><li><strong>权限沙箱</strong>：本地「<code>workspace-write</code> + <code>on-request</code>」，CI「指定沙箱 + <code>never</code>」，放权优先 <code>--add-dir</code>。</li><li><strong>模型与强度</strong>：旗舰 <code>gpt-5.5</code> + <code>medium</code> 打天下，弃用模型别碰。</li><li><strong>进阶入口</strong>：MCP 走 <code>codex mcp</code>、子代理靠 <code>[agents]</code>、Skills 用 <code>/skills</code>。</li></ul><p><strong>你现在应该能</strong>：丢掉那个歪歪扭扭的备忘 txt，要哪条命令、哪个配置键、哪个档位，扫一眼这页就走，拿不准时一句 <code>--help</code> 兜底，不用再开浏览器现翻文档。</p><hr><p>下一篇〔<a href="./36-best-practices">36 最佳实践</a> 〕是整个 Codex 篇的收尾。速查表解决的是「记不住」，最佳实践解决的是「用得对」——同样一条 <code>codex exec</code>，有人拿它跑出一条顺滑的自动化流水线，有人拿它把代码库搅得一团乱。留个小思考：<strong>你手上这些命令，哪几条是你天天在用、却从没想过有没有更稳的用法？</strong> 下一篇咱们就把这些「天天用却没想透」的地方，一个个掰开。</p>`,85)])])}const k=t(a,[["render",s]]);export{g as __pageData,k as default};
